// nodes/noteNode.js
import { BaseNode } from './BaseNode';
import { StickyNote } from 'lucide-react';

export const NoteNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="Note"
      icon={StickyNote}
      accentColor="var(--accent-amber)"
      inputs={[]}
      outputs={[]}
      style={{ opacity: 0.95 }}
      selected={selected}
    >
      <div style={{ 
        fontSize: '12px', 
        color: '#fde68a', 
        background: 'rgba(245, 158, 11, 0.1)', 
        padding: '12px', 
        borderRadius: '6px', 
        minHeight: '60px',
        border: '1px solid rgba(245, 158, 11, 0.2)'
      }}>
        {data?.note || 'Add a note in the inspector…'}
      </div>
    </BaseNode>
  );
};
